import { MathStudioConfig } from '../../types';

const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

const hasCarry = (n1: number, n2: number): boolean => {
    const s1 = n1.toString().split('').reverse();
    const s2 = n2.toString().split('').reverse();
    const len = Math.max(s1.length, s2.length);
    let carry = 0;
    for (let i = 0; i < len; i++) {
        const d1 = parseInt(s1[i] || '0');
        const d2 = parseInt(s2[i] || '0');
        if (d1 + d2 + carry >= 10) return true;
        carry = Math.floor((d1 + d2 + carry) / 10);
    }
    return false;
};

const hasBorrow = (n1: number, n2: number): boolean => {
    const s1 = n1.toString().split('').reverse();
    const s2 = n2.toString().split('').reverse();
    for (let i = 0; i < s2.length; i++) {
        if (parseInt(s1[i]) < parseInt(s2[i])) return true;
    }
    return false;
};

export const generateMathOperationsFast = (config: MathStudioConfig, count: number = 20) => {
    const operations = [];
    const min1 = Math.pow(10, config.digitCount1 - 1);
    const max1 = Math.pow(10, config.digitCount1) - 1;
    const min2 = Math.pow(10, config.digitCount2 - 1);
    const max2 = Math.pow(10, config.digitCount2) - 1;

    for (let i = 0; i < count; i++) {
        const opType = config.operations[getRandomInt(0, config.operations.length - 1)];
        let n1, n2, ans, valid = false;
        let attempts = 0;

        while (!valid && attempts < 100) {
            attempts++;
            n1 = getRandomInt(min1, max1);
            n2 = getRandomInt(min2, max2);

            if (opType === 'add') {
                if (!config.constraints.allowCarry && hasCarry(n1, n2)) continue;
                ans = n1 + n2;
                valid = true;
            } else if (opType === 'sub') {
                if (n1 < n2) [n1, n2] = [n2, n1];
                if (!config.constraints.allowBorrow && hasBorrow(n1, n2)) continue;
                ans = n1 - n2;
                valid = true;
            } else if (opType === 'mult') {
                ans = n1 * n2;
                valid = true;
            } else if (opType === 'div') {
                if (n2 === 0) continue;
                if (!config.constraints.allowRemainder) {
                    n1 = n2 * getRandomInt(1, 20);
                }
                ans = Math.floor(n1 / n2);
                valid = true;
            }
        }

        const unknownPos = config.constraints.findUnknown ? (['n1', 'n2', 'ans'][getRandomInt(0, 2)] as any) : 'ans';

        operations.push({
            n1, n2, op: opType === 'add' ? '+' : opType === 'sub' ? '-' : opType === 'mult' ? 'x' : '÷',
            ans, unknownPos
        });
    }

    return operations;
};

import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { MathStudioConfig } from '../../types';

export const generateMathProblemsAI = async (config: MathStudioConfig) => {
    const prompt = `
    [ROL: ÜST DÜZEY MATEMATİK ÖĞRETİM TASARIMCISI]
    GÖREV: ${config.gradeLevel} seviyesinde, "${config.problemConfig.topic}" temalı, ${config.problemConfig.count} adet matematik problemi üret.

    KURALLAR:
    1. İşlem Sayısı: Her problem ${config.problemConfig.steps} aşamalı/işlemli olmalı.
    2. İşlem Türleri: Sadece şu işlemleri kullan: ${config.operations.join(', ')}.
    3. Dil: Disleksi dostu, kısa ve net cümleler. Karmaşık bağlaçlardan kaçın.
    4. Sayılar: ${config.gradeLevel} seviyesine uygun büyüklükte sayılar seç.

    ÇIKTI (JSON):
    {
        "problems": [
            {
                "text": "Problem metni buraya...",
                "steps": ["1. işlem açıklaması", "2. işlem açıklaması"],
                "answer": "Cevap",
                "hint": "İpucu (Gerekirse)"
            }
        ]
    }
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            problems: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        text: { type: Type.STRING },
                        steps: { type: Type.ARRAY, items: { type: Type.STRING } },
                        answer: { type: Type.STRING },
                        hint: { type: Type.STRING }
                    },
                    required: ['text', 'answer']
                }
            }
        },
        required: ['problems']
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-pro-preview');
};

