                                    style={{ 
                                        minHeight: comp.style.h,
                                        zIndex: comp.style.zIndex,
                                        marginTop: comp.instanceId.includes('header') ? '0' : '20px'
                                    }}
                                >
                                    {renderComponentContent(comp)}
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>

            <ShareModal isOpen={isShareModalOpen} onClose={() => setIsShareModalOpen(false)} onShare={() => {}} />
        </div>
    );
};

