                                {item.type === 'analog_clock' && <ClockRenderer data={item.data} />}
                                {item.type === 'fraction_visual' && <FractionRenderer data={item.data} />}

                                {/* Selection Handles */}
                                {selectedId === item.id && (
                                    <>
                                        <div className="absolute -top-3 -right-3 w-6 h-6 bg-red-500 rounded-full flex items-center justify-center text-white cursor-pointer shadow-md hover:scale-110" onClick={(e) => { e.stopPropagation(); removeItem(item.id); }}>
                                            <i className="fa-solid fa-times text-xs"></i>
                                        </div>
                                        <div className="absolute -bottom-3 -right-3 w-6 h-6 bg-blue-500 rounded-full cursor-se-resize shadow-md"></div>
                                    </>
                                )}
                            </div>
                        ))}
                    </div>
                </div>

                {/* Right: Properties Panel */}
                <div className="w-80 bg-[#18181b] border-l border-zinc-800 flex flex-col overflow-y-auto">
                    <div className="p-4 border-b border-zinc-800">
                        <h3 className="font-bold text-zinc-400 text-xs uppercase tracking-widest">
                            {selectedItem ? 'Bileşen Ayarları' : 'Sayfa Ayarları'}
                        </h3>
                    </div>

                    <div className="p-4 space-y-6">
                        {!selectedItem ? (
                            <>
                                <div>
                                    <label className="text-xs font-bold text-zinc-500 mb-2 block">Kağıt Tipi</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {['blank', 'grid', 'dot'].map(t => (
                                            <button 
                                                key={t}
                                                onClick={() => setPageConfig({...pageConfig, paperType: t as any})}
                                                className={`p-2 rounded border text-xs capitalize ${pageConfig.paperType === t ? 'bg-blue-600 border-blue-600' : 'bg-zinc-800 border-zinc-700 hover:border-zinc-600'}`}
                                            >
                                                {t === 'blank' ? 'Boş' : t === 'grid' ? 'Kareli' : 'Noktalı'}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            </>
                        ) : (
                            <>
                                {selectedItem.type === 'operation_drill' && (
                                    <>
                                        <div>
                                            <label className="text-xs font-bold text-zinc-500 mb-2 block">İşlem Türü</label>
                                            <select 
                                                value={selectedItem.data.opType} 
                                                onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, opType: e.target.value } })}
                                                className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm outline-none"
                                            >
                                                <option value="add">Toplama (+)</option>
                                                <option value="sub">Çıkarma (-)</option>
                                                <option value="mult">Çarpma (x)</option>
                                                <option value="div">Bölme (÷)</option>
                                                <option value="mixed">Karışık</option>
                                            </select>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            <div>
                                                <label className="text-xs font-bold text-zinc-500 mb-1 block">Adet</label>
                                                <input type="number" value={selectedItem.data.count} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, count: Number(e.target.value) } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                            </div>
                                            <div>
                                                <label className="text-xs font-bold text-zinc-500 mb-1 block">Sütun</label>
                                                <input type="number" value={selectedItem.data.cols} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, cols: Number(e.target.value) } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                            </div>
                                        </div>
                                        <div>
                                            <label className="text-xs font-bold text-zinc-500 mb-2 block">Sayı Aralığı</label>
                                            <div className="flex gap-2 items-center">
                                                <input type="number" value={selectedItem.settings.rangeMin} onChange={e => updateItem(selectedItem.id, { settings: { ...selectedItem.settings, rangeMin: Number(e.target.value) } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                                <span>-</span>
                                                <input type="number" value={selectedItem.settings.rangeMax} onChange={e => updateItem(selectedItem.id, { settings: { ...selectedItem.settings, rangeMax: Number(e.target.value) } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                            </div>
                                        </div>
                                        <div className="space-y-2 pt-2">
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input type="checkbox" checked={selectedItem.settings.allowCarry} onChange={e => updateItem(selectedItem.id, { settings: { ...selectedItem.settings, allowCarry: e.target.checked } })} />
                                                <span className="text-sm">Eldeli / Onluk Bozma</span>
                                            </label>
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input type="checkbox" checked={selectedItem.data.orientation === 'vertical'} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, orientation: e.target.checked ? 'vertical' : 'horizontal' } })} />
                                                <span className="text-sm">Alt Alta (Dikey)</span>
                                            </label>
                                            <label className="flex items-center gap-2 cursor-pointer">
                                                <input type="checkbox" checked={selectedItem.data.showAnswer} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, showAnswer: e.target.checked } })} />
                                                <span className="text-sm text-green-500">Cevapları Göster</span>
                                            </label>
                                        </div>
                                    </>
                                )}

                                {selectedItem.type === 'fraction_visual' && (
                                    <>
                                        <div className="grid grid-cols-2 gap-2">
                                            <div>
                                                <label className="text-xs font-bold text-zinc-500 mb-1 block">Pay</label>
                                                <input type="number" value={selectedItem.data.numerator} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, numerator: Number(e.target.value) } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                            </div>
                                            <div>
                                                <label className="text-xs font-bold text-zinc-500 mb-1 block">Payda</label>
                                                <input type="number" value={selectedItem.data.denominator} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, denominator: Number(e.target.value) } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                            </div>
                                        </div>
                                        <div>
                                            <label className="text-xs font-bold text-zinc-500 mb-2 block">Tip</label>
                                            <div className="flex bg-zinc-800 rounded p-1">
                                                {['pie', 'bar'].map(t => (
                                                    <button key={t} onClick={() => updateItem(selectedItem.id, { data: { ...selectedItem.data, visualType: t } })} className={`flex-1 py-1 text-xs capitalize ${selectedItem.data.visualType === t ? 'bg-zinc-600 text-white' : 'text-zinc-400'}`}>{t}</button>
                                                ))}
                                            </div>
                                        </div>
                                    </>
                                )}

                                {selectedItem.type === 'analog_clock' && (
                                     <>
                                        <div>
                                            <label className="text-xs font-bold text-zinc-500 mb-1 block">Zaman (SS:DD)</label>
                                            <input type="text" value={selectedItem.data.time} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, time: e.target.value } })} className="w-full p-2 bg-zinc-800 border border-zinc-700 rounded text-sm" />
                                        </div>
                                        <label className="flex items-center gap-2 cursor-pointer mt-2">
                                            <input type="checkbox" checked={selectedItem.data.showNumbers} onChange={e => updateItem(selectedItem.id, { data: { ...selectedItem.data, showNumbers: e.target.checked } })} />
                                            <span className="text-sm">Rakamları Göster</span>
                                        </label>
                                     </>
                                )}

                                <div className="pt-6 mt-6 border-t border-zinc-800">
                                    <div className="grid grid-cols-2 gap-2">
                                        <div><label className="text-[10px] text-zinc-500 block">X</label><input type="number" value={selectedItem.x} onChange={e => updateItem(selectedItem.id, { x: Number(e.target.value) })} className="w-full p-1 bg-zinc-900 border border-zinc-800 rounded text-xs" /></div>
                                        <div><label className="text-[10px] text-zinc-500 block">Y</label><input type="number" value={selectedItem.y} onChange={e => updateItem(selectedItem.id, { y: Number(e.target.value) })} className="w-full p-1 bg-zinc-900 border border-zinc-800 rounded text-xs" /></div>
                                        <div><label className="text-[10px] text-zinc-500 block">Genişlik</label><input type="number" value={selectedItem.w} onChange={e => updateItem(selectedItem.id, { w: Number(e.target.value) })} className="w-full p-1 bg-zinc-900 border border-zinc-800 rounded text-xs" /></div>
                                        <div><label className="text-[10px] text-zinc-500 block">Yükseklik</label><input type="number" value={selectedItem.h} onChange={e => updateItem(selectedItem.id, { h: Number(e.target.value) })} className="w-full p-1 bg-zinc-900 border border-zinc-800 rounded text-xs" /></div>
                                    </div>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>

            <ShareModal isOpen={isShareModalOpen} onClose={() => setIsShareModalOpen(false)} onShare={() => {}} />
        </div>
    );
};

