    | 'fraction_visual' 
    | 'analog_clock' 
    | 'number_line' 
    | 'geometry_shape' 
    | 'base10_block';

export interface MathComponentBase {
    id: string;
    type: MathComponentType;
    x: number;
    y: number;
    w: number;
    h: number;
    isSelected?: boolean;
}

export interface MathHeaderComponent extends MathComponentBase {
    type: 'header';
    data: {
        title: string;
        subtitle: string;
        studentLabel: string; // "Ad Soyad:"
        dateLabel: string; // "Tarih:"
        style: 'simple' | 'boxed' | 'exam' | 'minimal';
        logoEnabled: boolean;
    };
}

export interface MathTextBlockComponent extends MathComponentBase {
    type: 'text_block';
    data: {
        text: string;
        fontSize: number;
        align: 'left' | 'center' | 'right' | 'justify';
        border: boolean;
        bgStyle: 'none' | 'grid' | 'lines' | 'dots';
    };
}

export interface MathDrillComponent extends MathComponentBase {
    type: 'operation_drill';
