        count: number;
        cols: number;
        gap: number;
        fontSize: number;
        opType: 'add' | 'sub' | 'mult' | 'div' | 'mixed';
        orientation: 'vertical' | 'horizontal';
        showAnswer: boolean;
        operations: any[];
    };
    settings: {
        digit1: number; 
        digit2: number; 
        rangeMin: number; 
        rangeMax: number; 
        allowCarry: boolean; 
        allowBorrow: boolean; 
        allowRemainder: boolean; 
        forceResultMax?: number; 
    };
}

export interface MathClockComponent extends MathComponentBase {
    type: 'analog_clock';
    data: {
        time: string;
        style: 'simple' | 'teaching' | 'roman' | 'minimal'; // teaching = dakika baloncukları
        showDigital: boolean;
        showMinuteMarks: boolean;
        colorHour: string;
        colorMinute: string;
        label: string;
    };
}

export interface MathFractionComponent extends MathComponentBase {
    type: 'fraction_visual';
    data: {
        numerator: number;
        denominator: number;
        visualType: 'pie' | 'bar' | 'group' | 'number_line' | 'polygon';
        groupIcon?: 'circle' | 'star' | 'apple' | 'cube';
        showLabel: boolean;
        color: string;
    };
