export interface MathNumberLineComponent extends MathComponentBase {
    type: 'number_line';
    data: {
        start: number;
        end: number;
        step: number;
        missingCount: number;
        showTicks: boolean;
        showArcs: boolean; // Toplama/Çıkarma yayları
