export interface MathShapeComponent extends MathComponentBase {
    type: 'geometry_shape';
    data: {
        shape: 'circle' | 'square' | 'triangle' | 'hexagon' | 'pentagon' | 'star' | 'cube' | 'cylinder' | 'cone' | 'pyramid' | 'sphere';
