        fill: boolean;
        strokeWidth: number;
        showVertices: boolean;
        showDimensions: boolean; // Kenar uzunlukları (a, b, h)
        label: string;
    };
}

export interface MathBase10Component extends MathComponentBase {
    type: 'base10_block';
    data: {
        number: number;
        showLabel: boolean;
        layout: 'row' | 'wrap';
    };
}

