                digit1: drillConfig.digit1,
                digit2: drillConfig.digit2,
                allowCarry: drillConfig.allowCarry,
                allowBorrow: drillConfig.allowBorrow,
                allowRemainder: drillConfig.allowRemainder
            });
            setGeneratedDrills(items);
        }
    }, [drillConfig, mode]);

