    const handleGenerateProblems = async () => {
        setIsGenerating(true);
        try {
            const prompt = `
            Konu: ${problemConfig.topic}. Seviye: ${problemConfig.difficulty}. 
            ${problemConfig.studentName ? `Öğrenci Adı: ${problemConfig.studentName}.` : ''}
