                                    <div>
                                        <label className="text-[9px] font-bold text-indigo-300 uppercase mb-1 block">Hangi İşlemler?</label>
                                        <div className="grid grid-cols-4 gap-2">
                                            {[
                                                {id:'add', label:'+'}, {id:'sub', label:'-'}, {id:'mult', label:'x'}, {id:'div', label:'÷'}
