                    </div>

                    {/* DRILL SETTINGS */}
                    {mode === 'drill' && (
                        <div className="p-5 space-y-6 animate-in slide-in-from-left-4">

                            {/* Operation Select */}
                            <div>
                                <label className="text-[10px] font-bold text-zinc-500 uppercase mb-2 block">İşlem Türleri (Çoklu)</label>
                                <div className="grid grid-cols-4 gap-2">
                                    {[
