                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => printService.generatePdf('#math-canvas', pageConfig.title, { action: 'download' })} className="w-9 h-9 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-file-pdf"></i></button>
