                                ))}
                            </div>
                            <div className="pt-4"><label className="block text-[10px] text-zinc-500 mb-1">Adet</label><input type="number" value={drillConfig.count} onChange={e => setDrillConfig({...drillConfig, count: Number(e.target.value)})} className="w-full bg-zinc-900 border border-zinc-700 rounded p-2 text-xs" /></div>
                        </div>
