                            <button onClick={handleGenerateProblems} disabled={isGenerating} className="w-full py-3 bg-white text-black font-bold rounded-xl text-sm">{isGenerating ? '...' : 'Problemleri Yaz'}</button>
                        </div>
                    )}
                </div>

                <div className="flex-1 bg-[#09090b] overflow-auto flex justify-center p-8 custom-scrollbar">
                    <div id="math-canvas" className="bg-white shadow-2xl relative flex flex-col p-10" style={{ width: `${A4_WIDTH_PX}px`, minHeight: `${A4_HEIGHT_PX}px`, height: 'auto' }}>
                        <div className="border-b-2 border-black pb-2 mb-4 flex justify-between items-center text-black">
                            <h1 className="text-2xl font-black uppercase">{pageConfig.title}</h1>
                            <span className="text-[10px] font-bold">Tarih: .................</span>
                        </div>
                        <div className="flex-1">
                            {mode === 'drill' ? (
                                <div className="grid w-full gap-y-10 gap-x-4" style={{ gridTemplateColumns: `repeat(${drillConfig.cols}, 1fr)` }}>
                                    {generatedDrills.map(op => <div key={op.id} className="flex justify-center items-start">{drillConfig.orientation === 'vertical' ? <OperationCardVertical op={op} fontSize={drillConfig.fontSize} showText={drillConfig.showTextRepresentation} /> : <OperationCardHorizontal op={op} fontSize={drillConfig.fontSize} showText={drillConfig.showTextRepresentation} />}</div>)}
                                </div>
                            ) : (
                                <div className="flex flex-col gap-6">
                                    {generatedProblems.map((prob, i) => <ProblemCard key={prob.id} problem={prob} showSolutionBox={problemConfig.includeSolutionBox} index={i} />)}
