                            )}
                        </div>
                        <div className="mt-4 pt-2 border-t border-zinc-200 flex justify-between items-center text-[9px] text-zinc-400 font-mono uppercase"><span>Bursa Disleksi AI</span><span>Sayfa 1</span></div>
