interface MathStudioProps {
    onBack: () => void;
    onAddToWorkbook?: (data: any) => void;
    initialData?: any;
}

export const MathStudio: React.FC<MathStudioProps> = ({ onBack, onAddToWorkbook, initialData }) => {
    const { user } = useAuth();
    const [mode, setMode] = useState<MathMode>('drill');
    const [isGenerating, setIsGenerating] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);

    const [pageConfig, setPageConfig] = useState<MathPageConfig>({ paperType: 'blank', gridSize: 20, margin: 40, showDate: true, showName: true, title: 'MATEMATİK ÇALIŞMASI' });
    const [drillConfig, setDrillConfig] = useState<MathDrillConfig>({ selectedOperations: ['add'], digit1: 2, digit2: 1, digit3: 1, count: 20, cols: 4, gap: 30, allowCarry: true, allowBorrow: true, allowRemainder: false, allowNegative: false, useThirdNumber: false, showTextRepresentation: false, autoFillPage: false, orientation: 'vertical', showAnswer: false, fontSize: 24 });
    const [problemConfig, setProblemConfig] = useState<MathProblemConfig>({ topic: 'Uzay Yolculuğu', count: 4, includeSolutionBox: true, studentName: '', selectedOperations: ['add', 'sub'], numberRange: '1-20', problemStyle: 'simple', complexity: '1-step' });

    const [generatedDrills, setGeneratedDrills] = useState<MathOperation[]>([]);
    const [generatedProblems, setGeneratedProblems] = useState<MathProblem[]>([]);

    useEffect(() => {
        if (initialData) {
            if (initialData.mode) setMode(initialData.mode);
            if (initialData.pageConfig) setPageConfig(initialData.pageConfig);
            if (initialData.mode === 'drill') {
                if (initialData.config) setDrillConfig(initialData.config);
                if (initialData.items) setGeneratedDrills(initialData.items);
            } else {
                if (initialData.config) setProblemConfig(initialData.config);
                if (initialData.items) setGeneratedProblems(initialData.items);
            }
        }
    }, [initialData]);

    useEffect(() => {
        if (mode === 'drill' && !initialData) {
            let targetCount = drillConfig.count;
            if (drillConfig.autoFillPage) {
                const usableHeight = A4_HEIGHT_PX - PAGE_MARGIN_Y - (pageConfig.margin * 2);
                const itemHeight = drillConfig.orientation === 'vertical' ? (drillConfig.fontSize * (drillConfig.useThirdNumber ? 4.5 : 3.2)) + (drillConfig.showTextRepresentation ? 12 : 0) + 15 : (drillConfig.fontSize * 1.5) + 15;
                const rows = Math.floor(usableHeight / itemHeight);
                const safeCols = drillConfig.orientation === 'vertical' && drillConfig.fontSize > 30 ? 3 : drillConfig.cols; 
                targetCount = Math.max(1, rows * safeCols);
            }
            const items = generateMathDrillSet(targetCount, drillConfig.selectedOperations as any, { digit1: drillConfig.digit1, digit2: drillConfig.digit2, digit3: drillConfig.digit3, allowCarry: drillConfig.allowCarry, allowBorrow: drillConfig.allowBorrow, allowRemainder: drillConfig.allowRemainder, allowNegative: drillConfig.allowNegative, useThirdNumber: drillConfig.useThirdNumber });
            setGeneratedDrills(items);
        }
    }, [drillConfig.selectedOperations, drillConfig.digit1, drillConfig.digit2, drillConfig.digit3, drillConfig.count, drillConfig.allowCarry, drillConfig.allowBorrow, drillConfig.allowRemainder, drillConfig.allowNegative, drillConfig.useThirdNumber, drillConfig.autoFillPage, drillConfig.fontSize, drillConfig.orientation, mode]);

    const handleGenerateProblems = async () => {
        setIsGenerating(true);
        try {
            const result = await generateMathProblemsAI(problemConfig);
            setGeneratedProblems((result.problems || []).map((p: any, i: number) => ({ id: `p-${Date.now()}-${i}`, text: p.text || "...", answer: p.answer || "?", operationHint: p.operationHint })));
        } catch (e) { alert("API Hatası."); } finally { setIsGenerating(false); }
    };

    const handleSave = async () => {
        if (!user) return;
        setIsSaving(true);
        try {
            const data = { mode, config: mode === 'drill' ? drillConfig : problemConfig, pageConfig, items: mode === 'drill' ? generatedDrills : generatedProblems, isMathStudio: true, title: pageConfig.title };
            await worksheetService.saveWorksheet(user.id, pageConfig.title, 'MATH_STUDIO' as ActivityType, [data], 'fa-solid fa-calculator', { id: 'math-logic', title: 'Matematik' });
            alert("Kaydedildi.");
        } catch (e) { alert("Hata."); } finally { setIsSaving(false); }
    };

    return (
        <div className="h-full flex flex-col bg-[#121212] text-white overflow-hidden font-sans">
            <div className="h-16 bg-[#18181b] border-b border-zinc-800 flex justify-between items-center px-6 shrink-0 z-50">
                <div className="flex items-center gap-4">
                    <button onClick={onBack} className="w-10 h-10 rounded-full bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-arrow-left"></i></button>
                    <h1 className="font-black text-xl tracking-tight text-white">MATH STUDIO</h1>
                </div>
                <div className="flex items-center gap-4">
                    <div className="flex bg-zinc-800 p-1 rounded-lg">
                        <button onClick={() => setMode('drill')} className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${mode === 'drill' ? 'bg-indigo-600 text-white shadow' : 'text-zinc-400'}`}>İşlem Atölyesi</button>
                        <button onClick={() => setMode('problem_ai')} className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${mode === 'problem_ai' ? 'bg-indigo-600 text-white shadow' : 'text-zinc-400'}`}>AI Problemleri</button>
