import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun yapay zeka motorusun.
Görevin: Disleksi, Diskalkuli ve DEHB tanısı almış veya risk grubundaki çocuklar için bilimsel temelli, hatasız ve JSON formatında eğitim materyali üretmek.
Sadece ham JSON döndür.
`;

export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method === 'OPTIONS') {
        res.setHeader('Access-Control-Allow-Origin', '*');
        res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
        return res.status(200).end();
    }

    if (req.method !== 'POST') {
        return res.status(405).json({ error: `Method ${req.method} Not Allowed` });
    }

    try {
        const { prompt, schema, image, model, mimeType, useSearch } = req.body;
        // Fixed: Ensure the API key check uses the pre-configured process.env.API_KEY
        if (!process.env.API_KEY) return res.status(500).json({ error: 'API anahtarı eksik.' });

        // Fixed: Standard initialization using named parameter and process.env.API_KEY directly
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Fixed: Removed forbidden models 'gemini-1.5-flash' and 'gemini-1.5-pro' and updated the fallback chain to use compliant models.
        const modelChain = [
            model || "gemini-3-flash-preview",
            "gemini-3-pro-preview"
        ];

        // Fixed: Updated configuration to match the supported keys in the @google/genai config object.
        const generationConfig = {
            systemInstruction: SYSTEM_INSTRUCTION,
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.7,
        };

        let contents: any[] = image ? [
            { parts: [{ inlineData: { mimeType: mimeType || 'image/jpeg', data: image } }, { text: prompt }] }
        ] : [
            { parts: [{ text: prompt }] }
        ];

        let lastError = null;
        for (const currentModel of modelChain) {
            try {
                // Fixed: Called generateContent with correct parameter structure.
                const response = await ai.models.generateContent({
                    model: currentModel,
                    contents: contents,
                    config: generationConfig,
                });

                // Fixed: Accessed .text property directly instead of calling it as a method.
                if (response.text) {
                    res.setHeader('Access-Control-Allow-Origin', '*');
                    res.setHeader('Content-Type', 'application/json; charset=utf-8');
                    return res.status(200).send(response.text);
                }
            } catch (error: any) {
                console.warn(`Model ${currentModel} failed, trying next...`);
                lastError = error;
            }
        }

        throw lastError || new Error("AI failed to generate content.");

    } catch (error: any) {
        console.error("API Handler Error:", error);
        return res.status(500).json({ error: error.message });
    }
}

