    const [isSidebarOpen, setIsSidebarOpen] = useState(window.innerWidth > 768);
    const [theme, setTheme] = useState<any>('anthracite');
    const [uiSettings, setUiSettings] = useState<UiSettings>(initialUiSettings);
    const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);

    // Worksheet State
    const [selectedActivity, setSelectedActivity] = useState<ActivityType | null>(null);
    const [worksheetData, setWorksheetData] = useState<WorksheetData>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [styleSettings, setStyleSettings] = useState<StyleSettings>(initialStyleSettings);
    const [studentProfile, setStudentProfile] = useState<StudentProfile | null>(null);

    // Restoration Data
    const [initialModuleData, setInitialModuleData] = useState<any>(null);

    const handleSelectActivity = (id: ActivityType | null) => {
        setSelectedActivity(id);
        setWorksheetData(null);
        setError(null);
        setInitialModuleData(null);
        if (id) setCurrentView('generator');
    };

    const onLoadSaved = (item: SavedWorksheet) => {
        const data = item.worksheetData?.[0];

        // 1. Math Studio Restoration
        if (item.activityType === 'MATH_STUDIO' || (data && data.isMathStudio)) {
            setInitialModuleData(data);
            setCurrentView('math-studio');
            return;
        }

        // 2. Reading Studio Restoration
        if (item.activityType === 'STORY_COMPREHENSION' && data?.layout) {
            setInitialModuleData(data);
            setCurrentView('reading-studio');
            return;
        }

        // 3. OCR Content Restoration
        if (item.activityType === 'OCR_CONTENT') {
            setInitialModuleData(data);
            setCurrentView('ocr');
            return;
        }

        // Standard Activity Restoration
        setSelectedActivity(item.activityType);
        setWorksheetData(item.worksheetData);
        if (item.styleSettings) setStyleSettings(item.styleSettings);
        if (item.studentProfile) setStudentProfile(item.studentProfile);
        setCurrentView('generator');
    };

    const handleSave = async (name: string, type: ActivityType, data: SingleWorksheetData[]) => {
        if (!user) { setIsAuthModalOpen(true); return; }
        try {
            const icon = ACTIVITIES.find(a => a.id === type)?.icon || 'fa-solid fa-file';
            const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(type)) || { id: 'others', title: 'Genel' };
            await worksheetService.saveWorksheet(user.id, name, type, data, icon, category, styleSettings, studentProfile || undefined);
        } catch (e) { console.error("Save error", e); }
    };

    return (
        <div className={`h-screen flex flex-col transition-colors duration-300 ${theme === 'light' ? 'theme-light' : 'dark'}`}>
            <header className="h-14 bg-zinc-900 border-b border-zinc-800 flex justify-between items-center px-4 shrink-0 z-50">
                <div className="flex items-center gap-4">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-zinc-400 hover:text-white transition-colors p-2">
                        <i className={`fa-solid ${isSidebarOpen ? 'fa-indent' : 'fa-outdent'} fa-lg`}></i>
                    </button>
                    <DyslexiaLogo className="h-8 w-auto" />
                </div>

                <div className="flex items-center gap-2">
                    <GlobalSearch onSelectActivity={handleSelectActivity} />
                    <button onClick={() => setCurrentView('generator')} className={`p-2 rounded-lg transition-all ${currentView === 'generator' ? 'bg-indigo-600 text-white' : 'text-zinc-400 hover:bg-zinc-800'}`} title="Ana Sayfa"><i className="fa-solid fa-house"></i></button>
                    <button onClick={() => setCurrentView('savedList')} className={`p-2 rounded-lg transition-all ${currentView === 'savedList' ? 'bg-indigo-600 text-white' : 'text-zinc-400 hover:bg-zinc-800'}`} title="Arşivim"><i className="fa-solid fa-box-archive"></i></button>
                    <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-zinc-400 hover:bg-zinc-800 rounded-lg"><i className="fa-solid fa-cog"></i></button>

                    <div className="h-6 w-px bg-zinc-700 mx-2"></div>

                    {user ? (
                        <button onClick={() => setCurrentView('profile')} className="flex items-center gap-2 group p-1 pr-3 rounded-full bg-zinc-800 border border-zinc-700 hover:border-indigo-500 transition-all">
                            <img src={user.avatar} className="w-7 h-7 rounded-full border border-zinc-600" />
                            <span className="text-xs font-bold text-zinc-300 group-hover:text-white hidden sm:block">{user.name}</span>
                        </button>
                    ) : (
                        <button onClick={() => setIsAuthModalOpen(true)} className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full text-xs font-bold transition-all shadow-lg">Giriş Yap</button>
                    )}
                </div>
            </header>

            <div className="flex-1 flex overflow-hidden">
                <Sidebar 
                    isSidebarOpen={isSidebarOpen} closeSidebar={() => setIsSidebarOpen(false)}
                    selectedActivity={selectedActivity} onSelectActivity={handleSelectActivity}
                    setWorksheetData={setWorksheetData} setIsLoading={setIsLoading}
                    setError={setError} isLoading={isLoading} onAddToHistory={() => {}}
                    onOpenOCR={() => setCurrentView('ocr')}
                    onOpenCurriculum={() => setCurrentView('curriculum')}
                    onOpenReadingStudio={() => setCurrentView('reading-studio')}
                    onOpenMathStudio={() => setCurrentView('math-studio')}
                />

                <main className="flex-1 overflow-hidden relative bg-zinc-950">
                    <Suspense fallback={<div className="h-full flex items-center justify-center"><div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div></div>}>
                        {currentView === 'ocr' ? <OCRScanner onBack={() => setCurrentView('generator')} onResult={() => {}} /> :
                         currentView === 'curriculum' ? <CurriculumView onBack={() => setCurrentView('generator')} onSelectActivity={handleSelectActivity} onStartCurriculumActivity={() => {}} /> :
                         currentView === 'reading-studio' ? <ReadingStudio onBack={() => setCurrentView('generator')} initialData={initialModuleData} /> :
                         currentView === 'math-studio' ? <MathStudio onBack={() => setCurrentView('generator')} initialData={initialModuleData} /> :
                         currentView === 'profile' ? <ProfileView onBack={() => setCurrentView('generator')} onSelectActivity={handleSelectActivity} /> :
                         <ContentArea 
                             currentView={currentView} onBackToGenerator={() => setCurrentView('generator')}
                             activityType={selectedActivity} worksheetData={worksheetData} isLoading={isLoading}
                             error={error} styleSettings={styleSettings} onStyleChange={setStyleSettings}
                             onSave={handleSave} onLoadSaved={onLoadSaved} onFeedback={() => {}} onOpenAuth={() => setIsAuthModalOpen(true)}
                             workbookItems={[]} setWorkbookItems={() => {}} workbookSettings={{} as any} setWorkbookSettings={() => {}}
                             onAddToWorkbook={() => {}} zenMode={false} toggleZenMode={() => {}}
                         />}
                    </Suspense>
                </main>
            </div>

            <AuthModal isOpen={isAuthModalOpen} onClose={() => setIsAuthModalOpen(false)} />
            <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} uiSettings={uiSettings} onUpdateUiSettings={setUiSettings} theme={theme} onUpdateTheme={setTheme} />
            <StudentInfoModal isOpen={isStudentModalOpen} onClose={() => setIsStudentModalOpen(false)} currentProfile={studentProfile} onSave={setStudentProfile} onClear={() => setStudentProfile(null)} />
        </div>
    );
};

