            <div className="flex-1 flex flex-col bg-zinc-50/50 dark:bg-black/50 overflow-hidden">
                <div className="p-6 border-b border-zinc-200 dark:border-zinc-800 flex justify-between items-center bg-white/80 dark:bg-zinc-900/80 backdrop-blur sticky top-0 z-10">
                    <h2 className="text-xl font-black text-zinc-800 dark:text-white">Kayıtlı İçerikler</h2>
                    <div className="relative w-64">
                        <i className="fa-solid fa-search absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400"></i>
                        <input type="text" placeholder="Ara..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-9 pr-4 py-2 bg-zinc-100 dark:bg-zinc-800 border-none rounded-xl text-sm outline-none" />
                    </div>
