import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { printService } from '../../utils/printService';
import { worksheetService } from '../../services/worksheetService';
import { EditableText } from '../Editable';
import { generateMathProblemsAI } from '../../services/generators/mathStudio';
import { generateMathDrillSet } from '../../services/offlineGenerators/mathStudio';
import { MathDrillConfig, MathPageConfig, MathOperation, MathProblemConfig, MathProblem, MathMode } from '../../types/math';
import { ActivityType } from '../../types';

const A4_WIDTH_PX = 794; 
const A4_HEIGHT_PX = 1123; 

const numberToTurkish = (num: number): string => {
    if (num === 0) return "Sıfır";
    const ones = ["", "Bir", "İki", "Üç", "Dört", "Beş", "Altı", "Yedi", "Sekiz", "Dokuz"];
    const tens = ["", "On", "Yirmi", "Otuz", "Kırk", "Elli", "Altmış", "Yetmiş", "Seksen", "Doksan"];
    const convertGroup = (n: number) => {
        let str = "";
        const h = Math.floor(n / 100);
        const t = Math.floor((n % 100) / 10);
        const o = n % 10;
        if (h === 1) str += "Yüz "; else if (h > 1) str += ones[h] + " Yüz ";
        if (t > 0) str += tens[t] + " ";
        if (o > 0) str += ones[o] + " ";
        return str.trim();
    };
    return num < 1000 ? convertGroup(num) : num.toString();
};

// Fix: Explicitly typed as React.FC to allow React internal props like 'key' and fix type assignment error at usage
const OperationCardVertical: React.FC<{ op: MathOperation, fontSize: number, showText: boolean }> = ({ op, fontSize, showText }) => (
    <div className="flex flex-col items-end font-mono font-bold leading-none break-inside-avoid p-1 text-black" style={{ fontSize: `${fontSize}px` }}>
        <div className="flex items-center gap-2">
