export const SavedWorksheetsView: React.FC<SavedWorksheetsViewProps> = ({ onLoad, onBack, targetUserId }) => {
    const { user } = useAuth();
    const [activeTab, setActiveTab] = useState<ArchiveTab>('materials');
    const [activeCategory, setActiveCategory] = useState<string>('all');
    const [worksheets, setWorksheets] = useState<SavedWorksheet[]>([]);
    const [assessments, setAssessments] = useState<SavedAssessment[]>([]);
    const [plans, setPlans] = useState<Curriculum[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');

    const effectiveUserId = targetUserId || user?.id;
    const isReadOnly = !!targetUserId && targetUserId !== user?.id;

    useEffect(() => {
        if (effectiveUserId) loadAllData();
        else setLoading(false);
    }, [effectiveUserId]);

    const loadAllData = async () => {
        setLoading(true);
        try {
            const [wsData, asData, plData] = await Promise.all([
                worksheetService.getUserWorksheets(effectiveUserId!, 0, 1000),
                assessmentService.getUserAssessments(effectiveUserId!),
                curriculumService.getUserCurriculums(effectiveUserId!)
            ]);
            setWorksheets(wsData.items);
            setAssessments(asData);
            setPlans(plData);
        } catch (e) { console.error(e); } finally { setLoading(false); }
    };

    const filteredItems = useMemo(() => {
        const query = searchQuery.toLowerCase();
        if (activeTab === 'materials') {
            return worksheets.filter(item => {
                const matchesSearch = item.name.toLowerCase().includes(query);
                if (activeCategory === 'all') return matchesSearch;

                // Studio/Modül filtreleri
                if (activeCategory === 'reading-studio') return matchesSearch && item.activityType === 'STORY_COMPREHENSION' && item.worksheetData?.[0]?.layout;
                if (activeCategory === 'math-studio') return matchesSearch && (item.activityType === 'MATH_STUDIO' || item.worksheetData?.[0]?.isMathStudio);
                if (activeCategory === 'ocr') return matchesSearch && item.activityType === 'OCR_CONTENT';

                const catId = ACTIVITY_CATEGORIES.find(c => c.activities.includes(item.activityType))?.id || item.category?.id;
                return matchesSearch && catId === activeCategory;
            });
        }
        if (activeTab === 'reports') return assessments.filter(item => item.studentName.toLowerCase().includes(query));
        if (activeTab === 'plans') return plans.filter(item => item.studentName.toLowerCase().includes(query));
        return [];
    }, [activeTab, activeCategory, searchQuery, worksheets, assessments, plans]);

    return (
        <div className="flex h-full bg-zinc-50 dark:bg-black rounded-2xl overflow-hidden border border-zinc-200 dark:border-zinc-800">
            <div className="w-64 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-800 flex flex-col p-4 shrink-0 overflow-y-auto custom-scrollbar">
                <div className="mb-6 flex items-center gap-2 px-2">
