                    <h3 className="font-black text-lg text-zinc-800 dark:text-white">Arşiv</h3>
                </div>

                <div className="space-y-1">
                    <FilterButton active={activeTab === 'materials'} label="Materyaller" icon="fa-solid fa-layer-group" onClick={() => { setActiveTab('materials'); setActiveCategory('all'); }} count={worksheets.length} />
                    <FilterButton active={activeTab === 'reports'} label="Raporlar" icon="fa-solid fa-file-medical" onClick={() => setActiveTab('reports')} count={assessments.length} />
                    <FilterButton active={activeTab === 'plans'} label="Eğitim Planları" icon="fa-solid fa-graduation-cap" onClick={() => { setActiveTab('plans'); setActiveCategory('plans'); }} count={plans.length} />
                </div>

                {activeTab === 'materials' && (
                    <div className="mt-6 pt-6 border-t border-zinc-100 dark:border-zinc-800">
                        <h4 className="px-2 text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-3">Modüller</h4>
                        <div className="space-y-0.5">
                            <button onClick={() => setActiveCategory('reading-studio')} className={`w-full text-left px-3 py-2 text-xs rounded-lg transition-colors flex items-center gap-2 ${activeCategory === 'reading-studio' ? 'bg-indigo-100 dark:bg-indigo-900 font-bold text-indigo-900 dark:text-white' : 'text-zinc-500 hover:text-zinc-800'}`}>
                                <i className="fa-solid fa-book-open-reader w-4"></i> Okuma Stüdyosu
                            </button>
                            <button onClick={() => setActiveCategory('math-studio')} className={`w-full text-left px-3 py-2 text-xs rounded-lg transition-colors flex items-center gap-2 ${activeCategory === 'math-studio' ? 'bg-indigo-100 dark:bg-indigo-900 font-bold text-indigo-900 dark:text-white' : 'text-zinc-500 hover:text-zinc-800'}`}>
                                <i className="fa-solid fa-calculator w-4"></i> Matematik Lab
                            </button>
                            <button onClick={() => setActiveCategory('ocr')} className={`w-full text-left px-3 py-2 text-xs rounded-lg transition-colors flex items-center gap-2 ${activeCategory === 'ocr' ? 'bg-indigo-100 dark:bg-indigo-900 font-bold text-indigo-900 dark:text-white' : 'text-zinc-500 hover:text-zinc-800'}`}>
                                <i className="fa-solid fa-wand-magic-sparkles w-4"></i> Akıllı Tarayıcı
