import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun yapay zeka motorusun.
Görevin: Disleksi, Diskalkuli ve DEHB tanısı almış veya risk grubundaki çocuklar için bilimsel temelli, hatasız ve JSON formatında eğitim materyali üretmek.
Sadece ham JSON döndür.
`;

export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method === 'OPTIONS') {
        res.setHeader('Access-Control-Allow-Origin', '*');
        res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
        return res.status(200).end();
    }

    if (req.method !== 'POST') {
        return res.status(405).json({ error: `Method ${req.method} Not Allowed` });
    }

    try {
        const { prompt, schema, image, model, mimeType, useSearch } = req.body;
        const apiKey = process.env.API_KEY;

        if (!apiKey) return res.status(500).json({ error: 'API anahtarı eksik.' });

        // Fix: Use process.env.API_KEY directly in constructor as per initialization guidelines
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Fix: Removed 'gemini-1.5-flash' (prohibited) and used updated model names from guidelines
        const modelChain = [
            model || "gemini-3-flash-preview",
            "gemini-flash-lite-latest"
        ];

        const generationConfig = {
            systemInstruction: SYSTEM_INSTRUCTION,
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.7,
            safetySettings: [
                { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
                { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
            ]
        };

        let contents: any[] = image ? [
            { parts: [{ inlineData: { mimeType: mimeType || 'image/jpeg', data: image } }, { text: prompt }] }
        ] : [
            { parts: [{ text: prompt }] }
        ];

        let lastError = null;
        for (const currentModel of modelChain) {
            try {
                const result = await ai.models.generateContent({
                    model: currentModel,
                    contents: contents,
                    config: generationConfig,
                });

                if (result.text) {
                    res.setHeader('Access-Control-Allow-Origin', '*');
                    res.setHeader('Content-Type', 'application/json; charset=utf-8');
                    return res.status(200).send(result.text);
                }
            } catch (error: any) {
                console.warn(`Model ${currentModel} failed, trying next...`);
                lastError = error;
            }
        }

        throw lastError || new Error("AI failed to generate content.");

    } catch (error: any) {
        console.error("API Handler Error:", error);
        return res.status(500).json({ error: error.message });
    }
}

import { GoogleGenAI } from "@google/genai";

// Helper to attempt JSON repair
const tryRepairJson = (jsonStr: string): any => {
    // 0. Remove Markdown
    let cleaned = jsonStr.replace(/```json\s*/gi, '').replace(/```\s*$/g, '').trim();

    try {
        return JSON.parse(cleaned);
    } catch (e) {
        console.warn("Primary JSON Parse failed, attempting repair...");

        // 1. Fix missing commas between objects in array (Common AI error: {...} {...})
        cleaned = cleaned.replace(/}\s*{/g, '},{');

        // 2. Balance Quotes (If cut off inside a string)
        let quoteCount = 0;
        for (let i = 0; i < cleaned.length; i++) {
            if (cleaned[i] === '"' && (i === 0 || cleaned[i-1] !== '\\')) quoteCount++;
        }
        if (quoteCount % 2 !== 0) {
            cleaned += '"';
        }

        // 3. Remove trailing comma (if cut off right after one: "item",)
        if (cleaned.trim().endsWith(',')) {
            cleaned = cleaned.trim().slice(0, -1);
        }

        // 4. Balance Brackets/Braces
        const openBraces = (cleaned.match(/{/g) || []).length;
        const closeBraces = (cleaned.match(/}/g) || []).length;
        const openBrackets = (cleaned.match(/\[/g) || []).length;
        const closeBrackets = (cleaned.match(/\]/g) || []).length;

        let repaired = cleaned;
        for (let i = 0; i < (openBraces - closeBraces); i++) repaired += '}';
        for (let i = 0; i < (openBrackets - closeBrackets); i++) repaired += ']';

        try {
            return JSON.parse(repaired);
        } catch (e2) {
             // 5. Aggressive Fallback: Find largest valid JSON substring
             const jsonObjectRegex = /{[\s\S]*}/;
             const jsonArrayRegex = /\[[\s\S]*\]/;
             const objectMatch = cleaned.match(jsonObjectRegex);
             const arrayMatch = cleaned.match(jsonArrayRegex);
             let bestMatch = null;

             if (objectMatch && arrayMatch) {
                 bestMatch = objectMatch[0].length > arrayMatch[0].length ? objectMatch[0] : arrayMatch[0];
             } else if (objectMatch) bestMatch = objectMatch[0];
             else if (arrayMatch) bestMatch = arrayMatch[0];

             if (bestMatch) {
                 try { return JSON.parse(bestMatch); } catch (e5) {}
             }

             console.error("JSON Repair Failed. Final attempt string:", repaired);
             throw new Error("Yapay zeka yanıtı onarılamadı.");
        }
    }
};

const SYSTEM_INSTRUCTION = `
Sen, Bursa Disleksi AI platformunun yapay zeka motorusun.
Görevin: Disleksi, Diskalkuli ve DEHB tanısı almış veya risk grubundaki çocuklar için bilimsel temelli, hatasız ve JSON formatında eğitim materyali üretmek.
Sadece ham JSON döndür, açıklama yapma.
`;

// --- CLIENT SIDE FALLBACK ---
const generateDirectly = async (params: { 
    prompt: string, 
    schema: any, 
    model?: string, 
    image?: string, 
    mimeType?: string,
    useSearch?: boolean 
}) => {
    if (!process.env.API_KEY) throw new Error("API Anahtarı eksik.");

    // Fix: Initialize GoogleGenAI using process.env.API_KEY directly in the named parameter object
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let contents: any[] = [];
    if (params.image) {
        const cleanBase64 = params.image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");
        contents = [{
            parts: [
                { inlineData: { mimeType: params.mimeType || 'image/jpeg', data: cleanBase64 } },
                { text: params.prompt }
            ]
        }];
    } else {
        contents = [{ parts: [{ text: params.prompt }] }];
    }

    // Default to gemini-3-flash-preview for best cost/performance
    const modelName = params.model || 'gemini-3-flash-preview';

    const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: params.schema,
    };

    if (params.useSearch) {
        config.tools = [{ googleSearch: {} }];
    }

    const response = await ai.models.generateContent({
        model: modelName,
        contents: contents,
        config: config
    });

    if (response.text) {
        return tryRepairJson(response.text);
    }
    throw new Error("Boş yanıt alındı.");
};

export const generateWithSchema = async (prompt: string, schema: any, model?: string, useSearch?: boolean) => {
    try {
        const response = await fetch('/api/generate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                prompt, 
                schema, 
                model: model || 'gemini-3-flash-preview',
                useSearch: useSearch || false
            }),
        });

        if (!response.ok) {
            return await generateDirectly({ prompt, schema, model, useSearch });
        }

        const fullText = await response.text();
        return tryRepairJson(fullText);

    } catch (error: any) {
        return await generateDirectly({ prompt, schema, model, useSearch });
    }
};

export const analyzeImage = async (base64Image: string, prompt: string, schema: any, model?: string) => {
    try {
        const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

        const response = await fetch('/api/generate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                prompt,
                schema,
                image: cleanBase64,
                mimeType: 'image/jpeg',
                model: model || 'gemini-3-flash-preview'
            }),
        });

        if (!response.ok) {
            return await generateDirectly({ prompt, schema, image: base64Image, model });
        }

        const fullText = await response.text();
        return tryRepairJson(fullText);

    } catch (error: any) {
        return await generateDirectly({ prompt, schema, image: base64Image, model });
    }
};

