export const SavedWorksheetsView: React.FC<SavedWorksheetsViewProps> = ({ onLoad, onBack, targetUserId }) => {
    const { user } = useAuth();
    const [activeTab, setActiveTab] = useState<ArchiveTab>('materials');
    const [activeCategory, setActiveCategory] = useState<string>('all');
    const [worksheets, setWorksheets] = useState<SavedWorksheet[]>([]);
    const [assessments, setAssessments] = useState<SavedAssessment[]>([]);
    const [plans, setPlans] = useState<Curriculum[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');

    const effectiveUserId = targetUserId || user?.id;
    const isReadOnly = !!targetUserId && targetUserId !== user?.id;

    useEffect(() => {
        if (effectiveUserId) loadAllData();
        else setLoading(false);
    }, [effectiveUserId]);

    const loadAllData = async () => {
        setLoading(true);
        try {
            const [wsData, asData, plData] = await Promise.all([
                worksheetService.getUserWorksheets(effectiveUserId!, 0, 1000),
                assessmentService.getUserAssessments(effectiveUserId!),
                curriculumService.getUserCurriculums(effectiveUserId!)
            ]);
            setWorksheets(wsData.items);
            setAssessments(asData);
            setPlans(plData);
        } catch (e) { console.error(e); } finally { setLoading(false); }
    };

    const filteredItems = useMemo(() => {
        const query = searchQuery.toLowerCase();
        if (activeTab === 'materials') {
            return worksheets.filter(item => {
                const matchesSearch = item.name.toLowerCase().includes(query);
                if (activeCategory === 'all') return matchesSearch;

                // Studio Module Filters
                const data = item.worksheetData?.[0];
                if (activeCategory === 'math-studio') return matchesSearch && (item.activityType === 'MATH_STUDIO' || (data && data.isMathStudio));
                if (activeCategory === 'reading-studio') return matchesSearch && (item.activityType === 'STORY_COMPREHENSION' && data?.layout);
                if (activeCategory === 'ocr') return matchesSearch && item.activityType === 'OCR_CONTENT';

                const categoryDef = ACTIVITY_CATEGORIES.find(c => c.activities.includes(item.activityType));
                return matchesSearch && (categoryDef?.id === activeCategory || item.category?.id === activeCategory);
            });
        }
        if (activeTab === 'reports') return assessments.filter(item => item.studentName.toLowerCase().includes(query));
        if (activeTab === 'plans') return plans.filter(item => item.studentName.toLowerCase().includes(query));
        return [];
    }, [activeTab, activeCategory, searchQuery, worksheets, assessments, plans]);

    return (
        <div className="flex h-full bg-zinc-50 dark:bg-black rounded-2xl overflow-hidden border border-zinc-200 dark:border-zinc-800">
            <div className="w-64 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 flex flex-col p-4 shrink-0 overflow-y-auto custom-scrollbar">
                <div className="mb-6 flex items-center gap-2 px-2">
                    <button onClick={onBack} className="w-8 h-8 rounded-full hover:bg-zinc-100 dark:hover:bg-zinc-800 flex items-center justify-center transition-colors">
                        <i className="fa-solid fa-arrow-left text-zinc-500"></i>
                    </button>
                    <h3 className="font-black text-lg text-zinc-800 dark:text-white">Arşiv</h3>
                </div>

                <div className="space-y-1">
                    <FilterButton active={activeTab === 'materials'} label="Materyaller" icon="fa-solid fa-layer-group" onClick={() => { setActiveTab('materials'); setActiveCategory('all'); }} count={worksheets.length} />
                    <FilterButton active={activeTab === 'reports'} label="Raporlar" icon="fa-solid fa-file-medical" onClick={() => setActiveTab('reports')} count={assessments.length} />
                    <FilterButton active={activeTab === 'plans'} label="Eğitim Planları" icon="fa-solid fa-graduation-cap" onClick={() => { setActiveTab('plans'); setActiveCategory('all'); }} count={plans.length} />
                </div>

                {activeTab === 'materials' && (
                    <div className="mt-6 pt-6 border-t border-zinc-100 dark:border-zinc-800">
                        <h4 className="px-2 text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-3">Modül Filtreleri</h4>
                        <div className="space-y-1">
                            <button onClick={() => setActiveCategory('reading-studio')} className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs transition-colors ${activeCategory === 'reading-studio' ? 'bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 font-bold' : 'text-zinc-500 hover:bg-zinc-50'}`}>
                                <i className="fa-solid fa-book-open-reader w-4"></i> Okuma Stüdyosu
                            </button>
                            <button onClick={() => setActiveCategory('math-studio')} className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs transition-colors ${activeCategory === 'math-studio' ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 font-bold' : 'text-zinc-500 hover:bg-zinc-50'}`}>
                                <i className="fa-solid fa-calculator w-4"></i> Matematik Lab
                            </button>
                            <button onClick={() => setActiveCategory('ocr')} className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs transition-colors ${activeCategory === 'ocr' ? 'bg-amber-50 dark:bg-amber-900/30 text-amber-600 font-bold' : 'text-zinc-500 hover:bg-zinc-50'}`}>
                                <i className="fa-solid fa-wand-magic-sparkles w-4"></i> Akıllı Tarayıcı
                            </button>
                        </div>
                    </div>
                )}
            </div>

            <div className="flex-1 flex flex-col min-w-0 bg-zinc-50/50 dark:bg-black/50 overflow-hidden">
                <div className="p-6 border-b border-zinc-200 dark:border-zinc-800 bg-white/80 dark:bg-zinc-900/80 backdrop-blur sticky top-0 z-10 flex justify-between items-center">
                    <SectionHeader title={activeTab === 'materials' ? 'Materyaller' : activeTab === 'reports' ? 'Raporlar' : 'Eğitim Planları'} count={filteredItems.length} icon={activeTab === 'materials' ? 'fa-solid fa-shapes' : activeTab === 'reports' ? 'fa-solid fa-clipboard-user' : 'fa-solid fa-calendar-check'} />
                    <div className="relative w-64">
