                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                    {loading ? <div className="text-center py-12">Yükleniyor...</div> : (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
                            {activeTab === 'materials' && filteredItems.map((item: any) => (
                                <MaterialCard key={item.id} item={item} onLoad={onLoad} onDelete={() => {}} isReadOnly={isReadOnly} />
                            ))}
                            {activeTab === 'plans' && filteredItems.map((item: any) => (
                                <div key={item.id} onClick={() => onLoad({ activityType: 'CURRICULUM_PLAN' as any, worksheetData: [item] } as any)} className="cursor-pointer">
