    fontStyle: 'normal', visualStyle: 'card', showPedagogicalNote: false, showMascot: false,
    showStudentInfo: false, showTitle: false, showInstruction: false, showImage: false,
    showFooter: false, smartPagination: false, fontFamily: 'OpenDyslexic', lineHeight: 1.5, letterSpacing: 0
};

const initialUiSettings: UiSettings = {
    fontFamily: 'OpenDyslexic', fontSizeScale: 1, letterSpacing: 'normal', lineHeight: 1.6, saturation: 100
};

type ModalType = 'settings' | 'history' | 'about' | 'developer';
type ExtendedView = View | 'ocr' | 'curriculum' | 'reading-studio' | 'math-studio';

interface ActiveCurriculumSession {
    planId: string;
    studentName: string;
    day: number;
    activityId: string;
    activityTitle: string;
}

const toPascalCase = (str: string): string => {
    return str.toLowerCase().split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join('');
};

const LoadingSpinner = () => (
    <div className="flex items-center justify-center h-full w-full min-h-[200px]">
        <div className="w-10 h-10 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
    </div>
);

const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
    if (!isOpen) return null;
    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4 animate-in fade-in duration-200" onClick={onClose}>
            <div className="bg-white dark:bg-zinc-800 rounded-2xl shadow-2xl w-full max-w-lg flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center p-5 border-b border-zinc-200 dark:border-zinc-700 bg-zinc-50 dark:bg-zinc-900 rounded-t-2xl">
                    <h3 className="text-xl font-bold text-zinc-900 dark:text-white">{title}</h3>
                    <button onClick={onClose} className="text-zinc-500 hover:text-zinc-800 dark:hover:text-zinc-300 w-8 h-8 flex items-center justify-center rounded-full hover:bg-zinc-200 dark:hover:bg-zinc-700 transition-colors">
                        <i className="fa-solid fa-times text-lg"></i>
                    </button>
                </div>
                <div className="p-6 overflow-y-auto custom-scrollbar">
                    {children}
                </div>
            </div>
        </div>
    );
};

const tourSteps: TourStep[] = [
    { targetId: 'tour-logo', title: 'Hoş Geldiniz', content: 'Bursa Disleksi AI platformuna hoş geldiniz. Hızlı bir tura başlayalım mı?', position: 'bottom' },
    { targetId: 'tour-search', title: 'Etkinlik Arama', content: 'İstediğiniz etkinliği veya konuyu buradan hızla bulabilirsiniz.', position: 'bottom' },
    { targetId: 'tour-sidebar', title: 'Kategoriler', content: 'Sol menüden etkinlik kategorilerine ulaşabilirsiniz.', position: 'right' },
    { targetId: 'tour-workbook-btn', title: 'Çalışma Kitapçığı', content: 'Seçtiğiniz etkinlikleri buraya ekleyerek tek bir PDF kitapçık oluşturabilirsiniz.', position: 'bottom' },
    { targetId: 'tour-ocr-btn', title: 'Akıllı Tarayıcı (OCR)', content: 'Fiziksel kağıtları tarayıp dijitalleştirmek için bu ikonu kullanın.', position: 'right' },
    { targetId: 'tour-history-btn', title: 'Geçmiş', content: 'Daha önce oluşturduğunuz etkinliklere buradan ulaşabilirsiniz.', position: 'bottom' },
];

const AppContent: React.FC = () => {
    const { user, logout } = useAuth();
    const [currentView, setCurrentView] = useState<ExtendedView>('generator');
    const [viewHistory, setViewHistory] = useState<ExtendedView[]>([]); 

    const [selectedActivity, setSelectedActivity] = useState<ActivityType | null>(null);
    const [worksheetData, setWorksheetData] = useState<WorksheetData>(null);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);

    const [activeCurriculumSession, setActiveCurriculumSession] = useState<ActiveCurriculumSession | null>(null);

    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [isSidebarExpanded, setIsSidebarExpanded] = useState(true);

    const [zenMode, setZenMode] = useState(false);

    const [openModal, setOpenModal] = useState<ModalType | null>(null);
    const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
    const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
    const [unreadCount, setUnreadCount] = useState(0);
    const [isTourOpen, setIsTourOpen] = useState(false);

    const [studentProfile, setStudentProfile] = useState<StudentProfile | null>(null);
    const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);

    const [workbookItems, setWorkbookItems] = useState<CollectionItem[]>([]);
    const [workbookSettings, setWorkbookSettings] = useState<WorkbookSettings>({
        title: 'Çalışma Kitapçığı', studentName: '', schoolName: '', year: new Date().getFullYear().toString(),
        teacherNote: '', theme: 'modern', accentColor: '#4f46e5', coverStyle: 'centered',
        showTOC: true, showPageNumbers: true, showWatermark: false, watermarkOpacity: 0.05, showBackCover: true
    });

    const [theme, setTheme] = useState<AppTheme>(() => {
        try { const storedTheme = localStorage.getItem('app-theme'); return (storedTheme as AppTheme) || 'anthracite'; } catch (e) { return 'anthracite'; }
    });

    const [uiSettings, setUiSettings] = useState<UiSettings>(() => {
        try { const stored = localStorage.getItem('app-ui-settings'); return stored ? { ...initialUiSettings, ...JSON.parse(stored) } : initialUiSettings; } catch (e) { return initialUiSettings; }
    });

    const [styleSettings, setStyleSettings] = useState<StyleSettings>(initialStyleSettings);

    const [historyItems, setHistoryItems] = useState<HistoryItem[]>(() => {
        try { const stored = localStorage.getItem('user_history'); return stored ? JSON.parse(stored) : []; } catch { return []; }
    });

    // Modül restorasyon verisi
    const [initialModuleData, setInitialModuleData] = useState<any>(null);

    const navigateTo = (view: ExtendedView) => {
        if (currentView === view) return;
        setViewHistory(prev => [...prev, currentView]);
        setCurrentView(view);
    };

    const handleGoBack = () => {
        if (currentView === 'generator' && activeCurriculumSession) { setActiveCurriculumSession(null); navigateTo('curriculum'); return; }
        if (viewHistory.length > 0) { const newHistory = [...viewHistory]; const prevView = newHistory.pop(); setViewHistory(newHistory); if (prevView) setCurrentView(prevView); } 
        else { setCurrentView('generator'); }
    };

    useEffect(() => { localStorage.setItem('user_history', JSON.stringify(historyItems)); }, [historyItems]);

    const addToHistory = (activityType: ActivityType, data: WorksheetData) => {
        const activity = ACTIVITIES.find(a => a.id === activityType);
        const category = ACTIVITY_CATEGORIES.find(c => c.activities.includes(activityType));
        if (!activity || !category) return;
        const newItem: HistoryItem = {
            id: Date.now().toString() + Math.random(), userId: user?.id || 'guest',
            activityType, data, timestamp: new Date().toISOString(), title: activity.title,
            category: { id: category.id, title: category.title }
        };
        setHistoryItems(prev => [newItem, ...prev].slice(0, 100));
    };

    const loadSavedWorksheet = (worksheet: SavedWorksheet) => {
        const data = worksheet.worksheetData?.[0];

        // 1. Math Studio Restorasyonu
        if (worksheet.activityType === 'MATH_STUDIO' || (data && data.isMathStudio)) {
            setInitialModuleData(data);
            navigateTo('math-studio');
            return;
        }

        // 2. Reading Studio Restorasyonu (Interaktif Mizanpaj)
        if (worksheet.activityType === 'STORY_COMPREHENSION' && data?.layout && data?.storyData) {
            setInitialModuleData(data);
            navigateTo('reading-studio');
            return;
        }

        // 3. OCR / Tarayıcı Restorasyonu
        if (worksheet.activityType === 'OCR_CONTENT') {
            setInitialModuleData(data);
            navigateTo('ocr');
            return;
        }

        // 4. Kitapçık
        if (worksheet.activityType === ActivityType.WORKBOOK) {
            if (worksheet.workbookItems && worksheet.workbookSettings) {
                setWorkbookItems(worksheet.workbookItems);
                setWorkbookSettings(worksheet.workbookSettings);
                navigateTo('workbook');
            }
            return;
        }

        // 5. Standart Etkinlik (Hızlı veya AI standart)
        setSelectedActivity(worksheet.activityType);
        setWorksheetData(worksheet.worksheetData);
        if (worksheet.styleSettings) setStyleSettings(worksheet.styleSettings);
        if (worksheet.studentProfile) setStudentProfile(worksheet.studentProfile);
        else setStudentProfile(null);
        setInitialModuleData(null);
        navigateTo('generator');
    };

    const handleSelectActivity = (activityType: ActivityType | null) => {
        if (currentView !== 'generator') navigateTo('generator');
        setActiveCurriculumSession(null);
        setSelectedActivity(activityType);
        setWorksheetData(null);
        setError(null);
        setInitialModuleData(null);
        setCurrentView('generator');
        if (isSidebarOpen) setIsSidebarOpen(false);
    };

    const handleStartCurriculumActivity = (planId: string, day: number, activityId: string, activityType: string, studentName: string, title: string) => {
        setActiveCurriculumSession({ planId, day, activityId, studentName, activityTitle: title });
        setStudentProfile({ name: studentName, school: '', grade: '', date: new Date().toLocaleDateString('tr-TR') });
        setSelectedActivity(activityType as ActivityType);
        setWorksheetData(null); 
        navigateTo('generator');
    };

    const handleCompleteCurriculumActivity = async () => {
        if (!activeCurriculumSession || !user) return;
        setIsLoading(true);
        try {
            if (worksheetData) {
                 await worksheetService.saveWorksheet(user.id, `${activeCurriculumSession.studentName} - ${activeCurriculumSession.activityTitle}`, selectedActivity!, worksheetData, 'fa-file', { id: 'curriculum', title: 'Plan' }, styleSettings, studentProfile || undefined);
            }
            await curriculumService.updateActivityStatus(activeCurriculumSession.planId, activeCurriculumSession.day, activeCurriculumSession.activityId, 'completed');
            setActiveCurriculumSession(null);
            navigateTo('curriculum');
        } catch (e) { console.error(e); } finally { setIsLoading(false); }
    };

    const handleAddToWorkbookGeneral = (activityType: ActivityType, data: any) => {
        if (activityType && data) {
            const dataArray = Array.isArray(data) ? data : [data];
            const newItems: CollectionItem[] = dataArray.map((sheet: any) => ({
                id: crypto.randomUUID(), activityType: activityType, data: sheet, settings: { ...styleSettings },
                title: sheet.title || ACTIVITIES.find(a => a.id === activityType)?.title || 'Etkinlik'
            }));
            setWorkbookItems(prev => [...prev, ...newItems]);
        }
    };

    return (
        <div className="flex flex-col h-screen bg-transparent font-sans transition-colors duration-300">
            <header className={`relative bg-[var(--panel-bg)] backdrop-blur-sm border-b border-[var(--border-color)] shadow-sm z-10 transition-all duration-500 ${zenMode ? '-mt-20 opacity-0 pointer-events-none' : 'mt-0 opacity-100'}`}>
                <div className="w-full px-4 sm:px-6 py-3 flex justify-between items-center">
                    <div className="flex items-center">
                        <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-[var(--text-muted)] mr-3 p-2 hover:text-[var(--text-primary)] transition-colors"><i className="fa-solid fa-bars fa-lg"></i></button>
                        <button id="tour-logo" onClick={() => { navigateTo('generator'); setSelectedActivity(null); setActiveCurriculumSession(null); }} className="flex items-center gap-3 px-2 py-1 rounded-lg relative z-50">
                            <DyslexiaLogo className="h-10 w-auto" />
                        </button>
                    </div>
                    <div className="flex items-center gap-2">
                        <GlobalSearch onSelectActivity={handleSelectActivity} />
                        <button onClick={() => setIsTourOpen(true)} className="p-2 text-[var(--text-secondary)] hover:text-[var(--accent-color)] rounded-md transition-all"><i className="fa-solid fa-question-circle fa-lg"></i></button>
                        <button id="tour-archive-btn" onClick={() => navigateTo('savedList')} className="p-2 text-[var(--text-secondary)] hover:text-[var(--accent-color)] rounded-md transition-all" title="Arşiv"><i className="fa-solid fa-box-archive fa-lg"></i></button>
                        {user ? (
                            <button id="tour-profile-btn" onClick={() => navigateTo('profile')} className="ml-2">
                                <img src={user.avatar} alt={user.name} className="w-9 h-9 rounded-full border-2 border-[var(--border-color)] hover:border-[var(--accent-color)] transition-colors bg-zinc-800" />
                            </button>
                        ) : (
                            <button onClick={() => setIsAuthModalOpen(true)} className="ml-2 px-5 py-2 bg-[var(--bg-paper)] text-[var(--text-primary)] border border-[var(--border-color)] rounded-lg font-black text-sm">Giriş Yap</button>
                        )}
                        <button onClick={() => setOpenModal('settings')} className="p-2 text-[var(--text-secondary)] hover:text-[var(--accent-color)] rounded-md transition-all"><i className="fa-solid fa-gear fa-lg"></i></button>
                    </div>
                </div>
            </header>

            <div className="flex flex-1 overflow-hidden">
                <Sidebar
                    isSidebarOpen={isSidebarOpen} closeSidebar={() => setIsSidebarOpen(false)}
                    selectedActivity={selectedActivity} onSelectActivity={handleSelectActivity}
                    setWorksheetData={setWorksheetData} setIsLoading={setIsLoading}
                    setError={setError} isLoading={isLoading} onAddToHistory={addToHistory}
                    isExpanded={isSidebarExpanded} onOpenStudentModal={() => setIsStudentModalOpen(true)}
                    studentProfile={studentProfile} styleSettings={styleSettings}
                    onOpenOCR={() => navigateTo('ocr')} onOpenCurriculum={() => navigateTo('curriculum')}
                    onOpenReadingStudio={() => navigateTo('reading-studio')} onOpenMathStudio={() => navigateTo('math-studio')}
                />

                <div className="flex-1 flex flex-col overflow-hidden" onMouseEnter={() => setIsSidebarExpanded(false)}>
                    <Suspense fallback={<div className="h-full flex items-center justify-center"><i className="fa-solid fa-circle-notch fa-spin text-4xl text-indigo-600"></i></div>}>
                        {currentView === 'reading-studio' ? <ReadingStudio onBack={handleGoBack} initialData={initialModuleData} onAddToWorkbook={(data: any) => handleAddToWorkbookGeneral('STORY_COMPREHENSION', data)} /> :
                         currentView === 'math-studio' ? <MathStudio onBack={handleGoBack} initialData={initialModuleData} onAddToWorkbook={(data: any) => handleAddToWorkbookGeneral('MATH_STUDIO' as any, data)} /> :
                         currentView === 'ocr' ? <OCRScanner onBack={handleGoBack} onResult={() => {}} /> :
                         currentView === 'curriculum' ? <CurriculumView onBack={handleGoBack} onSelectActivity={handleSelectActivity} onStartCurriculumActivity={handleStartCurriculumActivity} /> :
                         <ContentArea
                            currentView={currentView as View} onBackToGenerator={() => { if(currentView !== 'generator') handleGoBack(); else { setSelectedActivity(null); setWorksheetData(null); setActiveCurriculumSession(null); } }}
                            activityType={selectedActivity} worksheetData={worksheetData} isLoading={isLoading} error={error}
                            styleSettings={styleSettings} onStyleChange={setStyleSettings} onSave={(n,t,d) => worksheetService.saveWorksheet(user!.id, n, t, d, 'fa-file', {id:'general', title:'Genel'}, styleSettings, studentProfile || undefined)}
                            onLoadSaved={loadSavedWorksheet} onFeedback={() => setIsFeedbackOpen(true)} onOpenAuth={() => setIsAuthModalOpen(true)}
                            workbookItems={workbookItems} setWorkbookItems={setWorkbookItems} workbookSettings={workbookSettings} setWorkbookSettings={setWorkbookSettings}
                            onAddToWorkbook={() => handleAddToWorkbookGeneral(selectedActivity!, worksheetData)} zenMode={zenMode} toggleZenMode={() => setZenMode(!zenMode)}
                            activeCurriculumSession={activeCurriculumSession} onCompleteCurriculumActivity={handleCompleteCurriculumActivity}
                        />}
                    </Suspense>
                </div>
            </div>

            <TourGuide steps={tourSteps} isOpen={isTourOpen} onClose={() => setIsTourOpen(false)} />
            <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} activityType={selectedActivity} />
            <AuthModal isOpen={isAuthModalOpen} onClose={() => setIsAuthModalOpen(false)} />
            <StudentInfoModal isOpen={isStudentModalOpen} onClose={() => setIsStudentModalOpen(false)} currentProfile={studentProfile} onSave={setStudentProfile} onClear={() => setStudentProfile(null)} />
            <SettingsModal isOpen={openModal === 'settings'} onClose={() => setOpenModal(null)} uiSettings={uiSettings} onUpdateUiSettings={setUiSettings} theme={theme} onUpdateTheme={setTheme} />
            <Modal isOpen={openModal === 'history'} onClose={() => setOpenModal(null)} title="İşlem Geçmişi"><HistoryView historyItems={historyItems} onRestore={() => {}} onSaveToArchive={() => {}} onDelete={() => {}} onClearAll={() => {}} onClose={() => setOpenModal(null)} /></Modal>
        </div>
    );
};

export const App: React.FC = () => {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { SavedWorksheet, SavedAssessment, Curriculum, ActivityType } from '../types';
import { ACTIVITIES, ACTIVITY_CATEGORIES } from '../constants';
import { useAuth } from '../context/AuthContext';
import { worksheetService } from '../services/worksheetService';
import { assessmentService } from '../services/assessmentService';
import { curriculumService } from '../services/curriculumService';
import { ShareModal } from './ShareModal';

interface SavedWorksheetsViewProps {
  onLoad: (worksheet: SavedWorksheet) => void;
  onBack: () => void;
  targetUserId?: string;
}

type ArchiveTab = 'materials' | 'reports' | 'plans';

