const FilterButton = ({ active, label, icon, onClick, count }: any) => (
    <button 
        onClick={onClick}
        className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all font-bold text-xs mb-1 group ${active ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200 dark:shadow-none' : 'text-zinc-500 hover:bg-zinc-100 dark:hover:bg-zinc-800'}`}
