            {showText && <span className="text-[0.4em] text-zinc-400 font-sans font-normal">({numberToTurkish(op.num1)})</span>}
        </div>
        <div className="flex items-center gap-2 w-full justify-end relative">
            <span className="absolute left-0 transform -translate-x-1/2">{op.symbol}</span>
            <span>{op.num2}</span>
            {showText && <span className="text-[0.4em] text-zinc-400 font-sans font-normal">({numberToTurkish(op.num2)})</span>}
        </div>
        {op.num3 !== undefined && (
            <div className="flex items-center gap-2 w-full justify-end relative">
                 <span className="absolute left-0 transform -translate-x-1/2">{op.symbol2 || op.symbol}</span>
                 <span>{op.num3}</span>
            </div>
        )}
        <div className="w-full border-b-2 border-black mb-1"></div>
        <span className="text-transparent select-none h-[1.2em] w-full text-right block border-2 border-zinc-200 border-dashed rounded text-zinc-300/50 bg-white">
            {op.answer}
        </span>
    </div>
);

const ProblemCard: React.FC<{ problem: MathProblem, showSolutionBox: boolean, index: number }> = ({ problem, showSolutionBox, index }) => (
    <div className="w-full mb-6 break-inside-avoid text-black">
        <div className="flex gap-3">
            <div className="w-6 h-6 rounded-full bg-indigo-600 text-white flex items-center justify-center font-bold text-xs shrink-0 mt-1 shadow-md">{index + 1}</div>
            <div className="flex-1">
                <p className="text-base font-medium leading-relaxed text-justify font-dyslexic border-b border-zinc-100 pb-1">
                    <EditableText value={problem.text} tag="span" />
                </p>
                {showSolutionBox && (
                    <div className="mt-2 w-full h-24 border border-zinc-300 border-dashed rounded-lg bg-zinc-50/30 relative flex items-end justify-between p-2">
                        <span className="text-[9px] font-bold text-zinc-300 uppercase tracking-widest absolute top-1 left-2">Çözüm</span>
                        <div className="text-right w-full"><span className="text-xs font-bold text-zinc-400 mr-2">Cevap:</span><span className="inline-block w-16 border-b-2 border-zinc-300"></span></div>
                    </div>
                )}
            </div>
        </div>
    </div>
);

export const MathStudio: React.FC<{ onBack: () => void; onAddToWorkbook?: (data: any) => void; initialData?: any }> = ({ onBack, onAddToWorkbook, initialData }) => {
    const { user } = useAuth();
    const [mode, setMode] = useState<MathMode>('drill');
    const [isSaving, setIsSaving] = useState(false);
    const [pageConfig, setPageConfig] = useState<MathPageConfig>({ paperType: 'blank', gridSize: 20, margin: 40, showDate: true, showName: true, title: 'MATEMATİK ÇALIŞMASI' });
    const [drillConfig, setDrillConfig] = useState<MathDrillConfig>({ selectedOperations: ['add'], digit1: 2, digit2: 1, digit3: 1, count: 20, cols: 4, gap: 30, allowCarry: true, allowBorrow: true, allowRemainder: false, allowNegative: false, useThirdNumber: false, showTextRepresentation: false, autoFillPage: false, orientation: 'vertical', showAnswer: false, fontSize: 24 });
    const [problemConfig, setProblemConfig] = useState<MathProblemConfig>({ topic: 'Uzay Yolculuğu', count: 4, includeSolutionBox: true, studentName: '', selectedOperations: ['add', 'sub'], numberRange: '1-20', problemStyle: 'simple', complexity: '1-step' });
    const [generatedDrills, setGeneratedDrills] = useState<MathOperation[]>([]);
    const [generatedProblems, setGeneratedProblems] = useState<MathProblem[]>([]);

    // Restorasyon mantığı
    useEffect(() => {
        if (initialData) {
            if (initialData.mode) setMode(initialData.mode);
            if (initialData.pageConfig) setPageConfig(initialData.pageConfig);
            if (initialData.mode === 'drill') {
                if (initialData.config) setDrillConfig(initialData.config);
                if (initialData.items) setGeneratedDrills(initialData.items);
            } else {
                if (initialData.config) setProblemConfig(initialData.config);
                if (initialData.items) setGeneratedProblems(initialData.items);
            }
        }
    }, [initialData]);

    useEffect(() => {
        if (mode === 'drill' && !initialData) {
            const items = generateMathDrillSet(drillConfig.count, drillConfig.selectedOperations as any, { digit1: drillConfig.digit1, digit2: drillConfig.digit2, digit3: drillConfig.digit3, allowCarry: drillConfig.allowCarry, allowBorrow: drillConfig.allowBorrow, allowRemainder: drillConfig.allowRemainder, allowNegative: drillConfig.allowNegative, useThirdNumber: drillConfig.useThirdNumber });
            setGeneratedDrills(items);
        }
    }, [drillConfig.selectedOperations, drillConfig.digit1, drillConfig.digit2, mode, initialData]);

    const handleSave = async () => {
        if (!user) return;
        setIsSaving(true);
        try {
            const data = { mode, config: mode === 'drill' ? drillConfig : problemConfig, pageConfig, items: mode === 'drill' ? generatedDrills : generatedProblems, isMathStudio: true, title: pageConfig.title };
            await worksheetService.saveWorksheet(user.id, pageConfig.title, 'MATH_STUDIO' as ActivityType, [data], 'fa-solid fa-calculator', { id: 'math-logic', title: 'Matematik' });
            alert("Kaydedildi.");
        } catch (e) { alert("Hata."); } finally { setIsSaving(false); }
    };

    return (
        <div className="h-full flex flex-col bg-zinc-950 text-white overflow-hidden">
            <div className="h-14 bg-zinc-900 border-b border-zinc-800 flex justify-between items-center px-4 shrink-0 z-50">
                <button onClick={onBack} className="w-10 h-10 rounded-full hover:bg-zinc-800 flex items-center justify-center text-zinc-400"><i className="fa-solid fa-arrow-left"></i></button>
                <div className="flex gap-2">
                    <button onClick={() => setMode('drill')} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${mode === 'drill' ? 'bg-indigo-600 text-white' : 'text-zinc-500'}`}>İşlem Atölyesi</button>
                    <button onClick={() => setMode('problem_ai')} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${mode === 'problem_ai' ? 'bg-indigo-600 text-white' : 'text-zinc-500'}`}>AI Problemleri</button>
                    <button onClick={handleSave} disabled={isSaving} className="px-4 py-1.5 bg-white text-black rounded-lg text-xs font-bold ml-4">Kaydet</button>
                </div>
            </div>
            <div className="flex-1 flex overflow-hidden">
                <div className="flex-1 bg-zinc-900 overflow-auto flex justify-center p-8 custom-scrollbar">
                    <div id="math-canvas" className="bg-white shadow-2xl relative flex flex-col p-10" style={{ width: `${A4_WIDTH_PX}px`, minHeight: `${A4_HEIGHT_PX}px`, height: 'auto' }}>
                        <div className="border-b-2 border-black pb-2 mb-4 flex justify-between items-center text-black">
                            <h1 className="text-2xl font-black uppercase tracking-tight">{pageConfig.title}</h1>
                        </div>
                        <div className="flex-1">
                            {mode === 'drill' ? (
                                <div className="grid w-full gap-8" style={{ gridTemplateColumns: `repeat(${drillConfig.cols}, 1fr)` }}>
                                    {generatedDrills.map(op => <OperationCardVertical key={op.id} op={op} fontSize={drillConfig.fontSize} showText={drillConfig.showTextRepresentation} />)}
                                </div>
                            ) : (
                                <div className="flex flex-col gap-6">
                                    {generatedProblems.map((prob, i) => <ProblemCard key={prob.id} problem={prob} showSolutionBox={problemConfig.includeSolutionBox} index={i} />)}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};
